    "starterCode": "for(int i=5; i>=1; i--){\n    if(i%2==0){\n        pen.c(1);\n    } else {\n        pen.c(15);\n    }\n    pen.up().moveTo(-(i*30)/2, -(i*30)/2).down();\n    pen.rr(i*30, i*30);\n}\n",
